# ─── Waveform Generator ───────────────────────────────────────────────────────
def make_waveform(t, freq, amp, kind):
    phase = 2 * np.pi * freq * t
    if kind == "sine":
        return amp * np.sin(phase)
    elif kind == "square":
        return amp * np.sign(np.sin(phase))
    else:  # triangle
        return amp * (2 / np.pi) * np.arcsin(np.sin(phase))

# ─── PLL Demodulator (simple first-order) ────────────────────────────────────
class PLL:
    """Simple first-order PLL for FM demodulation."""
    def __init__(self, sr, fc, bandwidth=200.0):
        self.sr = sr
        self.fc = fc
        self.phase = 0.0
        self.freq = fc
        # Loop filter gain
        self.kp = 2 * np.pi * bandwidth / sr
        self.ki = self.kp * self.kp / 4.0

        self.integrator = 0.0

    def process(self, samples):
        out = np.zeros(len(samples))
        for i, s in enumerate(samples):
            # VCO output
            vco = np.cos(self.phase)
            # Phase detector (multiply + low-pass approximation)
            pd = s * (-np.sin(self.phase))
            # Loop filter
            self.integrator += self.ki * pd
            freq_correction = self.kp * pd + self.integrator
            # Update VCO frequency & phase
            self.freq = self.fc + freq_correction * self.sr / (2 * np.pi)
            self.phase += 2 * np.pi * self.freq / self.sr
            self.phase %= (2 * np.pi)
            out[i] = freq_correction  # proportional to instantaneous freq deviation
        return out

# ─── Audio Engine ─────────────────────────────────────────────────────────────
class AudioEngine:
    def __init__(self):
        self.sr = SAMPLE_RATE
        self.carrier_phase = 0.0
        self.mod_phase = 0.0
        self.pll = PLL(self.sr, CARRIER_FREQ, bandwidth=300.0)
        self.output_queue = queue.Queue(maxsize=8)
        self._lock = threading.Lock()

        # Buffers for visualisation (ring buffers)
        self.vis_len = 2048
        self.buf_mod = np.zeros(self.vis_len)
        self.buf_fm  = np.zeros(self.vis_len)
        self.buf_dem = np.zeros(self.vis_len)

    def _generate_block(self, frames):
        mf  = float(state["mod_freq"])
        ma  = float(state["mod_amp"])
        wf  = state["waveform"]

        # ── Modulating signal ──────────────────────────────────────────────
        t_mod = (self.mod_phase + np.arange(frames)) / self.sr
        mod_sig = make_waveform(t_mod, mf, ma, wf)
        self.mod_phase = (self.mod_phase + frames) % self.sr

        # ── FM carrier ────────────────────────────────────────────────────
        inst_freq = CARRIER_FREQ + MAX_DEVIATION * mod_sig
        phase_inc = 2 * np.pi * inst_freq / self.sr
        phases = self.carrier_phase + np.cumsum(phase_inc)
        fm_sig = np.sin(phases)
        self.carrier_phase = phases[-1] % (2 * np.pi)

        # ── PLL demodulation ──────────────────────────────────────────────
        dem_sig = self.pll.process(fm_sig)
        # Normalise demodulated signal for audio output
        peak = np.max(np.abs(dem_sig)) + 1e-9
        audio_out = dem_sig / peak * 0.6

        # ── Update visualisation buffers ──────────────────────────────────
        with self._lock:
            self.buf_mod = np.roll(self.buf_mod, -frames)
            self.buf_mod[-frames:] = mod_sig
            self.buf_fm  = np.roll(self.buf_fm,  -frames)
            self.buf_fm[-frames:]  = fm_sig
            self.buf_dem = np.roll(self.buf_dem, -frames)
            self.buf_dem[-frames:] = audio_out

        return audio_out

    def callback(self, outdata, frames, time_info, status):
        audio = self._generate_block(frames)
        outdata[:] = audio.reshape(-1, 1)

    def get_vis_buffers(self):
        with self._lock:
            return self.buf_mod.copy(), self.buf_fm.copy(), self.buf_dem.copy()

    def start(self):
        self.stream = sd.OutputStream(
            samplerate=self.sr,
            channels=1,
            blocksize=BLOCK_SIZE,
            dtype='float32',
            callback=self.callback,
        )
        self.stream.start()
        print("Audio stream started.")

    def stop(self):
        self.stream.stop()
        self.stream.close()
        print("Audio stream stopped.")

